package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	accounts map[string]int
	mu       sync.RWMutex
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]int),
	}
}

func (b *Bank) Deposit(account string, amount int) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[account] += amount
}

func (b *Bank) Withdraw(account string, amount int) bool {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.accounts[account] >= amount {
		b.accounts[account] -= amount
		return true
	}
	return false
}

func (b *Bank) Balance(account string) int {
	b.mu.RLock()
	defer b.mu.RUnlock()
	return b.accounts[account]
}

func main() {
	bank := NewBank()
	var wg sync.WaitGroup

	// Simulate concurrent deposits and withdrawals
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			bank.Deposit("account1", 100)
		}()
	}

	for i := 0; i < 5; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			bank.Withdraw("account1", 50)
		}()
	}

	wg.Wait()
	fmt.Println("Final balance:", bank.Balance("account1"))
}